class SurveysPage{constructor(){this.surveys=[],this.userResponses=[],this.currentUser=null,this.init()}async init(){this.setupEventListeners(),this.loadCurrentUser(),await this.loadUserResponses(),await this.loadSurveys()}setupEventListeners(){const s=document.getElementById("create-survey-btn");s&&s.addEventListener("click",()=>{window.surveyApp&&window.surveyApp.showCreateSurveyModal()});const e=document.getElementById("logout-btn");e&&e.addEventListener("click",()=>window.app.logout())}loadCurrentUser(){window.app&&window.app.currentUser&&(this.currentUser=window.app.currentUser,this.updateUIForUserRole())}updateUIForUserRole(){const s=document.getElementById("create-survey-btn");s&&this.currentUser&&("admin"===this.currentUser.role?s.classList.remove("hidden"):s.classList.add("hidden"))}async loadUserResponses(){try{window.app&&window.app.isLoggedIn()&&(this.userResponses=await window.app.apiRequest("/surveys/my/data"))}catch(s){}}async loadSurveys(){const s=document.getElementById("loading"),e=document.getElementById("error-message"),n=document.getElementById("surveys-container");try{s.classList.remove("hidden"),e.classList.add("hidden"),n.classList.add("hidden"),this.surveys=await window.app.apiRequest("/surveys"),s.classList.add("hidden"),n.classList.remove("hidden"),this.renderSurveys()}catch(n){s.classList.add("hidden"),e.classList.remove("hidden")}}renderSurveys(){const s=document.getElementById("surveys-list");s.innerHTML="",0!==this.surveys.length?this.surveys.forEach(e=>{const n=this.userResponses&&Array.isArray(this.userResponses)&&this.userResponses.some(s=>s.survey_id===e.id),t=this.createSurveyCard(e,n);s.appendChild(t)}):s.innerHTML=`\n                <div class="empty-state">\n                    <h2>Опросов пока нет</h2>\n                    <p>${this.currentUser&&"admin"===this.currentUser.role?"Создайте первый опрос для начала работы.":"Опросы появятся здесь, когда администраторы их создадут."}</p>\n                    ${this.currentUser&&"admin"===this.currentUser.role?'<button class="btn btn-primary" onclick="window.surveyApp.showCreateSurveyModal()">➕ Создать опрос</button>':""}\n                </div>\n            `}createSurveyCard(s,e){const n=document.createElement("div");n.className="survey-card";const t=this.getStatusBadge(s.status),r=this.getActionButton(s,e);return n.innerHTML=`\n            <div class="survey-card-content">\n                <div class="survey-header">\n                    <h3>${s.title}</h3>\n                    <div class="survey-meta">\n                        ${t}\n                        <span class="survey-date">${new Date(s.created_at).toLocaleDateString("ru-RU")}</span>\n                    </div>\n                </div>\n                <div class="survey-content">\n                    <p>${s.description||"Без описания"}</p>\n                </div>\n                <div class="survey-actions">\n                    ${r}\n                    ${this.currentUser&&"admin"===this.currentUser.role?`\n                        <a href="/admin/surveys/${s.id}" class="btn btn-secondary btn-sm">\n                            ✏️ Редактировать\n                        </a>\n                        <a href="/surveys/${s.id}/results" class="btn btn-secondary btn-sm">\n                            📊 Результаты\n                        </a>\n                    `:""}\n                </div>\n            </div>\n        `,n}getStatusBadge(s){const e={draft:'<span class="status-badge draft">📝 Черновик</span>',open:'<span class="status-badge open">📢 Открыт</span>',closed:'<span class="status-badge closed">🔒 Закрыт</span>'};return e[s]||e.draft}getActionButton(s,e){if(e){const e=this.userResponses&&Array.isArray(this.userResponses)&&this.userResponses.find(e=>e.survey_id===s.id);if(e)return`\n                    <a href="/surveys/responses/${e.id}" class="btn btn-secondary btn-sm">\n                        📝 Мои ответы\n                    </a>\n                `}return"open"===s.status?`\n                <a href="/surveys/${s.id}/take" class="btn btn-primary btn-sm">\n                    📝 Пройти опрос\n                </a>\n            `:"closed"===s.status?`\n                <a href="/surveys/${s.id}/results" class="btn btn-secondary btn-sm">\n                    📊 Результаты\n                </a>\n            `:'<span class="btn btn-secondary btn-sm" disabled>📝 Недоступен</span>'}}document.addEventListener("DOMContentLoaded",()=>{window.surveysPage=new SurveysPage});